import './TimelineVertical.scss';

import React, { useMemo } from 'react';

import type { AtomPosition, TimelineIconType } from '../Timeline.types';
import { TimelineCollapse } from '../TimelineCollapse';
import { calcAtomType, calcStepPosition } from '../utils';
import { CollapsableFutureVerticalTimeline } from './CollapsableFutureVerticalTimeline';
import { CollapsableVerticalTimeline } from './CollapsableVerticalTimeline';
import { CurrentStepVerticalTimeline } from './CurrentStepVerticalTimeline';
import type { TimelineVerticalProps } from './TimelineVertical.types';
import { VerticalContent } from './VerticalContent';

export const TimelineVertical: React.FC<TimelineVerticalProps> = ({
	steps = [],
	activeStepIndex,
	onCollapse,
	collapsed = false,
	collapsable = false,
	completed = false,
}) => {
	const stepsLength = steps.length;

	const sliceIndex = useMemo(() => {
		if (completed) {
			return stepsLength - 1;
		}

		if (activeStepIndex === -1) {
			return -1;
		}

		if (activeStepIndex >= 0) {
			return activeStepIndex;
		}

		return stepsLength;
	}, [activeStepIndex, completed, stepsLength]);

	const stepsMap = useMemo(
		() => ({
			collapsed: steps.slice(0, Math.max(0, sliceIndex)),
			current: steps.slice(sliceIndex, Math.min(sliceIndex + 1, stepsLength)),
			inactive: steps.slice(sliceIndex + 1, stepsLength),
		}),
		[sliceIndex, steps, stepsLength],
	);

	if (!stepsLength) {
		return null;
	}

	const takenStepsCount = () => {
		if (completed) {
			return stepsLength;
		}

		if (activeStepIndex >= 0) {
			return activeStepIndex;
		}

		return 0;
	};

	return (
		<div data-testid="TimelineVertical">
			{collapsable && (
				<>
					<TimelineCollapse
						collapsed={collapsed}
						onCollapse={onCollapse}
						amountStepsCount={stepsLength}
						takenStepsCount={takenStepsCount()}
						completed={completed}
						pastSteps
					>
						<CollapsableVerticalTimeline steps={stepsMap.collapsed} />
					</TimelineCollapse>

					<CurrentStepVerticalTimeline
						steps={stepsMap.current}
						completed={completed}
						collapsable={collapsable}
						collapsed={collapsed}
						bottom={sliceIndex === stepsLength - 1}
					/>
					<TimelineCollapse collapsed={collapsed} completed={completed}>
						<CollapsableFutureVerticalTimeline steps={stepsMap.inactive} completed={completed} />
					</TimelineCollapse>
				</>
			)}

			{!collapsable && (
				<>
					{steps.map((step, index) => {
						const { error, id } = step;
						const position: AtomPosition = calcStepPosition(index, stepsLength - 1);
						const type: TimelineIconType = completed ? 'active' : calcAtomType(index, activeStepIndex, error);

						return <VerticalContent {...step} key={id} type={type} position={position} />;
					})}
				</>
			)}
		</div>
	);
};
